import { supabase } from './supabase';
export default {
  async search(email) {
    const {
      data,
      error
    } = await supabase.from('customers').select('*').ilike('email', `%${email}%`).limit(5);
    if (error) throw error;
    return data || [];
  },
  async getByEmail(email) {
    const {
      data,
      error
    } = await supabase.from('customers').select('*').eq('email', email).maybeSingle();
    if (error) throw error;
    return data;
  },
  async create(customer) {
    const {
      data,
      error
    } = await supabase.from('customers').insert({
      email: customer.email,
      name: customer.name,
      phone: customer.phone
    }).select().single();
    if (error) throw error;
    return data;
  },
  async createOrUpdate(customer) {
    const existing = await this.getByEmail(customer.email);
    if (existing) {
      const {
        data,
        error
      } = await supabase.from('customers').update({
        name: customer.name,
        phone: customer.phone,
        updated_at: new Date().toISOString()
      }).eq('email', customer.email).select().single();
      if (error) throw error;
      return data;
    } else {
      return await this.create(customer);
    }
  }
};
